(function(){
  if(window.Alpine){return;}
  console.warn('[SummitLink] 本地 Alpine fallback 已加载（降级模式）');
  var AlpineStub={
    version:'0.0.0-stub',
    start:function(){
      var body=document.body;
      if(body&&body.hasAttribute('x-cloak')) body.removeAttribute('x-cloak');
      document.dispatchEvent(new CustomEvent('alpine:init'));
      document.dispatchEvent(new CustomEvent('alpine:initialized'));
    }
  };
  window.Alpine=AlpineStub;
  if(document.readyState==='loading'){
    document.addEventListener('DOMContentLoaded',function(){AlpineStub.start();},{once:true});
  }else{
    AlpineStub.start();
  }
})();
